  describe("Claim — deductible per damage event", () => {
    it.todo("should apply the 100 G deductible once per damaged item (sword 500 + amulet 300 → 600 G)");
  });

  describe("Claim — rounding", () => {
    it.todo("should round the final payout down to the previous whole G");
  });

  describe("Claim — cap based on unmodified insurance sum", () => {
    it.todo("should cap a sword+amulet policy at 3200 G (sum 1600)");
    it.todo("should cap a sword+3-runes policy at 3500 G (sum 1750, block discount does not lower the sum)");
    it.todo("should cap a two-sword policy at 4000 G (sum 2000)");
