    it.todo("should limit a later claim to the remaining cap (second claim 1500 → payout 600, remaining 0)");
  });

  describe("Claim — multiple items of the same type", () => {
    it.todo("should treat each same-type damage entry as a separate damage with its own deductible");
  });

  describe("CLI scenario output shape", () => {
    it.todo("should return a results array of the same length and order as the input steps");
    it.todo("should return { premium } for a quote step and { payout, remainingCap } for a claim step");
