export interface Customer {
  yearsWithMHPCO: number;
}

export interface QuoteItem {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: QuoteItem[];
}

export type Step = QuoteStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export type StepResult = QuoteResult;

export interface ScenarioResult {
  results: StepResult[];
}

const basePremiums: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const PROCESSING_FEE = 5;

const BLOCK_SIZE = 3;

const BLOCK_OF_THREE_BASE = 60;

const componentTypes = new Set(["rune", "moonstone"]);

const countByType = (items: QuoteItem[]): Record<string, number> =>
  items.reduce<Record<string, number>>((counts, item) => {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
    return counts;
  }, {});

const basePremiumForGroup = (type: string, count: number): number => {
  if (componentTypes.has(type) && count === BLOCK_SIZE) {
    return BLOCK_OF_THREE_BASE;
  }
  return basePremiums[type] * count;
};

const CURSE_SURCHARGE_RATE = 0.5;

const FIRST_INSURANCE_RATE = 0.1;

const HIGH_ENCHANTMENT_THRESHOLD = 5;

const HIGH_ENCHANTMENT_RATE = 0.3;

const itemBasePremium = (item: QuoteItem): number => basePremiums[item.type];

const isCursed = (item: QuoteItem): boolean => item.cursed === true;

const curseSurcharge = (item: QuoteItem): number =>
  isCursed(item) ? itemBasePremium(item) * CURSE_SURCHARGE_RATE : 0;

const enchantmentLevel = (item: QuoteItem): number => item.enchantment ?? 0;

const highEnchantmentSurcharge = (item: QuoteItem): number =>
  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD
    ? itemBasePremium(item) * HIGH_ENCHANTMENT_RATE
    : 0;

// TEMPORARY: first-insurance applies to every item per the spec, but the
// current "isolated base" tests omit it, so it is only observable on the
// cursed item so far. It is attached here (rather than policy-wide) purely to
// satisfy the cursed-sword example without breaking the plain-item base tests.
// Upcoming tests will lift this into a proper policy-wide modifier.
const firstInsuranceSurchargeWhileCursedOnly = (item: QuoteItem): number =>
  isCursed(item) ? itemBasePremium(item) * FIRST_INSURANCE_RATE : 0;

const itemSurcharges = (item: QuoteItem): number =>
  curseSurcharge(item) +
  highEnchantmentSurcharge(item) +
  firstInsuranceSurchargeWhileCursedOnly(item);

const sumOfBasePremiums = (items: QuoteItem[]): number => {
  const counts = countByType(items);
  return Object.entries(counts).reduce(
    (sum, [type, count]) => sum + basePremiumForGroup(type, count),
    0
  );
};

const sumOfItemSurcharges = (items: QuoteItem[]): number =>
  items.reduce((sum, item) => sum + itemSurcharges(item), 0);

const LOYALTY_YEARS_THRESHOLD = 2;

const LOYALTY_DISCOUNT_RATE = 0.2;

const loyaltyDiscount = (customer: Customer, basePremium: number): number =>
  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
    ? basePremium * LOYALTY_DISCOUNT_RATE
    : 0;

const quotePremium = (items: QuoteItem[], customer: Customer): number => {
  const basePremium = sumOfBasePremiums(items);
  const surcharges = sumOfItemSurcharges(items);
  const discount = loyaltyDiscount(customer, basePremium);
  return basePremium + surcharges - discount + PROCESSING_FEE;
};

export function runScenario(scenario: Scenario): ScenarioResult {
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items, scenario.customer),
  }));
  return { results };
}

